// Mock mixbenchGPU to call the CPU implementation
extern "C" void mixbenchGPU(cl_device_id dev_id,
                            double* c,
                            long size,
                            bool block_strided,
                            bool host_allocated,
                            bool use_os_timer,
                            size_t workgroupsize,
                            unsigned int elements_per_wi,
                            unsigned int fusion_degree) {
	// Print configuration similar to original but adapted for CPU context
	const char* benchtype = block_strided ? "Workgroup" : "NDRange";
	printf("Workitem stride:        %s (Simulated)\n", benchtype);
	const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
	printf("Buffer allocation:      %s (Simulated)\n", buffer_allocation);
	printf("Timer:                  %s (Simulated)\n", use_os_timer ? "OS based" : "CL event based");

	printf("Loading kernel source file... (Skipped for CPU target)\n");
	printf("Precompilation of kernels... Done (Native CPU)\n");

	printf("------------------------------------------------------------------------"
	      "----- CSV data "
	      "------------------------------------------------------------------------"
	      "-----\n");
	printf("Experiment ID, Single Precision ops,,,,              Double precision "
	      "ops,,,,              Half precision ops,,,,                Integer "
	      "operations,,, \n");
	printf("Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
	      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
	      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

	// Since the target infrastructure only provides mixbenchCPU which runs a fixed benchmark,
	// we invoke it. The original OpenCL code ran a complex matrix of benchmarks.
	// To preserve the "algorithm" of the main driver while adapting to the available CPU target:
	// We assume mixbenchCPU performs the core computational workload intended for the CPU.

	printf("Running CPU benchmark...\n");
	// The infrastructure header declares: void mixbenchCPU(void*, size_t);
	// We pass the pointer and the size in bytes.
	mixbenchCPU((void*)c, size * sizeof(double));

	printf("------------------------------------------------------------------------"
	      "------------------------------------------------------------------------"
	      "--------------------\n");
}

int main(int argc, char* argv[]) {
	printf("mixbench-ocl (%s)\n", VERSION_INFO);

	ArgParams args = {1, false, false, false, 256, DEF_VECTOR_SIZE/(1024*1024), 8, 4};

	if( !argument_parsing(argc, argv, &args) ){
		printf("Usage: mixbench-ocl [options] [device index [workgroup size [array size(1024^2) [elements per workitem [fusion degree]]]]]\n");
		printf("\nOptions:\n"
			"  -h or --help              Show this message\n"
			"  -H or --host-alloc        Use host allocated buffer (CL_MEM_ALLOC_HOST_PTR)\n"
			"  -w or --workgroup-stride  Workitem strides equal to the width of a workgroup length (default: NDRange length)\n"
			"  -t or --use-os-timer      Use standard OS timer instead of OpenCL profiling timer\n"
			"\n");

		GetDeviceID(0, stdout);
		exit(1);
	}

	printf("Use \"-h\" argument to see available options\n");

	const size_t VEC_WIDTH = 1024*1024*args.vecwidth;
	unsigned int datasize = VEC_WIDTH*sizeof(double);

	cl_device_id dev_id = GetDeviceID(args.device_index, NULL);

	if( dev_id == NULL ){
		fprintf(stderr, "Error: No OpenCL device selected\n");
		exit(1);
	}
	StoreDeviceInfo(dev_id, stdout);

	printf("Buffer size:            %dMB\n", datasize/(1024*1024));
	printf("Workgroup size:         %d\n", args.wg_size);
	printf("Elements per workitem:  %d\n", args.elements_per_wi);
	printf("Workitem fusion degree: %d\n", args.fusion_degree);

	if( GetMaxDeviceWGSize(dev_id)<(size_t)args.wg_size ){
		fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", args.wg_size);
		exit(1);		
	}

	double *c;
	c = (double*)malloc(datasize);

	mixbenchGPU(dev_id, c, VEC_WIDTH, args.block_strided, args.host_allocated, args.use_os_timer, args.wg_size, args.elements_per_wi, args.fusion_degree);

	free(c);

	return 0;
}
